#define RADIUS 7
#define BLOCK_SIZE 256

void stencil_1d(const int *in, int *out, int length)
{
  int num_blocks = length / BLOCK_SIZE;

  #pragma omp parallel
  {
    int thread_id = omp_get_thread_num();
    int num_threads = omp_get_num_threads();

    int block_id = thread_id;
    if (block_id >= num_blocks) return;

    int gindex_start = block_id * BLOCK_SIZE;

    int temp[BLOCK_SIZE + 2 * RADIUS];

    for (int t = 0; t < BLOCK_SIZE; t++) {
      int gindex = gindex_start + t;
      int lindex = t + RADIUS;
      temp[lindex] = in[gindex];
    }

    for (int t = 0; t < RADIUS; t++) {
      int gindex = gindex_start + t;
      int lindex = t + RADIUS;
      temp[lindex - RADIUS] = (gindex < RADIUS) ? 0 : in[gindex - RADIUS];
      temp[lindex + BLOCK_SIZE] = in[gindex + BLOCK_SIZE];
    }

    #pragma omp barrier

    for (int t = 0; t < BLOCK_SIZE; t++) {
      int gindex = gindex_start + t;
      int lindex = t + RADIUS;

      int result = 0;
      for (int offset = -RADIUS; offset <= RADIUS; offset++)
        result += temp[lindex + offset];

      out[gindex] = result;
    }
  }
}

