        for(z = 0; nz > z; z++)
            for(y = 0; ny > y; y++)
                for(x = 0; nx > x; x++)
                {
                    c = x + y * nx + z * nx * ny;

                    w = (0 == x) ? c      : c - 1;
                    e = (nx - 1 == x) ? c : c + 1;
                    n = (0 == y) ? c      : c - nx;
                    s = (ny - 1 == y) ? c : c + nx;
                    b = (0 == z) ? c      : c - nx * ny;
                    t = (nz - 1 == z) ? c : c + nx * ny;

                    tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp; 
        i++;
    }
    while(numiter > i);

