void lud_internal_omp(float *m, int matrix_dim, int offset, int num_blocks)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];
  int i, j, k;
  float sum;

  int blk_row, blk_col;
  #pragma omp parallel for
  for (blk_row=0; blk_row < num_blocks; blk_row++) {
    for (blk_col=0; blk_col < num_blocks; blk_col++) {
      int global_row_id = offset + (blk_row+1)*BLOCK_SIZE;
      int global_col_id = offset + (blk_col+1)*BLOCK_SIZE;

      for (j=0; j < BLOCK_SIZE; j++) {
        for (i=0; i < BLOCK_SIZE; i++) {
          peri_row[j][i] = m[(offset+j)*matrix_dim+global_col_id+i];
