        for (i=0; i < BLOCK_SIZE; i++) {
          sum = 0;
          for (k=0; k < BLOCK_SIZE; k++)
            sum += peri_col[j][k] * peri_row[k][i];
          m[(global_row_id+j)*matrix_dim+global_col_id+i] -= sum;
        }
      }
    }
  }
}

void lud_omp(float *m, int matrix_dim)
{
  int i=0;
  int num_blocks;

  for (i=0; matrix_dim-BLOCK_SIZE > i; i += BLOCK_SIZE) {
      lud_diagonal_omp(m, matrix_dim, i);
      num_blocks = (matrix_dim-i)/BLOCK_SIZE-1;
      if (num_blocks > 0) {
        lud_perimeter_omp(m, matrix_dim, i, num_blocks);
        lud_internal_omp(m, matrix_dim, i, num_blocks);
      }
  }
  lud_diagonal_omp(m, matrix_dim, i);
}

